import { useEffect, useState } from "react";
import { Toaster } from "react-hot-toast";
import { useAppStore } from "./store/appStore";
import LoginPage from "./pages/LoginPage";
import DashboardPage from "./pages/DashboardPage";
import SettingsPage from "./pages/SettingsPage";

export default function App() {
  const { token, user, init } = useAppStore();
  const [screen, setScreen] = useState("dashboard");

  useEffect(() => {
    init();
  }, [init]);

  if (!token || !user) {
    return (
      <>
        <LoginPage />
        <Toaster position="top-right" />
      </>
    );
  }

  return (
    <div className="min-h-screen bg-slate-100">
      <header className="border-b border-slate-200 bg-white">
        <div className="mx-auto flex max-w-7xl items-center justify-between px-6 py-4">
          <div className="flex items-center">
            <img src="/full-logo.png" alt="Email Validator" className="h-16 w-auto" />
          </div>
          <div className="flex items-center gap-2">
            <button className={`btn ${screen === "dashboard" ? "btn-primary" : "btn-outline"}`} onClick={() => setScreen("dashboard")}>Dashboard</button>
            <button className={`btn ${screen === "settings" ? "btn-primary" : "btn-outline"}`} onClick={() => setScreen("settings")}>Settings</button>
          </div>
        </div>
      </header>
      <main className="mx-auto max-w-7xl px-6 py-6">
        {screen === "dashboard" ? <DashboardPage /> : <SettingsPage />}
      </main>
      <Toaster position="top-right" />
    </div>
  );
}
